// mm/src/api/refresh.js
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '';
const DEFAULT_REFRESH_URL = 'https://manuscriptmagic.fowkes.xyz/services/refresh.php';

function getRefreshUrl() {
  // If you set REACT_APP_API_BASE_URL, we assume endpoints are:
  //   {API_BASE}/refresh
  // Otherwise default to your hosted PHP endpoint.
  return API_BASE ? `${API_BASE}/refresh` : DEFAULT_REFRESH_URL;
}

/**
 * Refresh tokens.
 * requires: refreshToken
 * returns: { success, message, accessToken, refreshToken }
 */
export const refreshTokens = async (refreshToken) => {
  if (!refreshToken) {
    return {
      success: false,
      message: 'Missing refresh token.',
    };
  }

  // DEV MOCK if no API_BASE AND you don't want to hit prod endpoint:
  // If you prefer always hitting your hosted PHP endpoint, delete this block.
  if (!API_BASE) {
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          data: {
            success: true,
            message: 'Mock refresh ok',
            accessToken: `mock_access_${Date.now()}`,
            refreshToken: `mock_refresh_${Date.now()}`,
          },
        });
      }, 350);
    });
  }

  const url = getRefreshUrl();
  const resp = await axios.post(
    url,
    { refreshToken },
    { headers: { 'Content-Type': 'application/json' } }
  );
  return resp;
};

// --- lightweight token storage helpers (shared) ---
export const tokenStore = {
  getAccessToken() {
    return localStorage.getItem('mm_accessToken') || '';
  },
  getRefreshToken() {
    return localStorage.getItem('mm_refreshToken') || '';
  },
  getUserId() {
    return localStorage.getItem('mm_userId') || '';
  },
  setTokens({ userId, accessToken, refreshToken }) {
    if (userId !== undefined && userId !== null) {
      localStorage.setItem('mm_userId', String(userId));
    }
    if (accessToken) localStorage.setItem('mm_accessToken', String(accessToken));
    if (refreshToken) localStorage.setItem('mm_refreshToken', String(refreshToken));
  },
  clear() {
    localStorage.removeItem('mm_userId');
    localStorage.removeItem('mm_accessToken');
    localStorage.removeItem('mm_refreshToken');
  },
};

/**
 * fetchWithAuth(url, options)
 * - Adds Authorization: Bearer <accessToken>
 * - If response is 401: calls refreshTokens() and retries once
 *
 * Use this later for any authenticated endpoint.
 */
export async function fetchWithAuth(url, options = {}) {
  const accessToken = tokenStore.getAccessToken();
  const refreshToken = tokenStore.getRefreshToken();

  const doFetch = async (token) => {
    const headers = new Headers(options.headers || {});
    if (token) headers.set('Authorization', `Bearer ${token}`);
    if (!headers.has('Content-Type') && options.body) {
      headers.set('Content-Type', 'application/json');
    }

    return fetch(url, {
      ...options,
      headers,
    });
  };

  // 1st attempt
  let res = await doFetch(accessToken);
  if (res.status !== 401) return res;

  // refresh + retry once
  if (!refreshToken) return res;

  try {
    const refreshed = await refreshTokens(refreshToken);
    const data = refreshed?.data || {};

    const newAccess = data.accessToken || data.AccessToken || '';
    const newRefresh = data.refreshToken || data.RenewalToken || data.RefreshToken || '';
    const ok = data.success === true || data.Success === true;

    if (!ok || !newAccess) return res;

    tokenStore.setTokens({ accessToken: newAccess, refreshToken: newRefresh || refreshToken });
    res = await doFetch(newAccess);
    return res;
  } catch (e) {
    return res;
  }
}
